// Get the raw rows from the previous Postgres node
const rows = items.map(item => item.json);

// 1. REVERSE ORDER
rows.reverse();

// 2. CLEAN AND FORMAT THE SCRIPT to prevent context bloat
const cleanHistory = rows.reduce((acc, row) => {
  let roleLabel = 'System'; 
  const sender = (row.sender || '').toLowerCase();

  if (sender === 'user') {
    roleLabel = 'User';
  } else if (sender === 'ai') {
    roleLabel = 'Assistant';
  } else if (sender === 'admin') {
    roleLabel = 'Support Agent'; 
  }

  let content = (row.content || '').trim();

  // --- CONTEXT BLOAT CLEANUP FILTERS ---

  // 1. Strip the duplicated System Prompt entirely
  // (The Agent node already has this, we don't need it in history)
  if (content.includes("## IDENTITY")) {
    const splitContent = content.split(/Human:|User:/i);
    // If the system prompt was bundled with the human message, extract just the human part
    if (splitContent.length > 1) {
      content = splitContent[1].trim();
    } else {
      // If it's a standalone system message row, skip it completely
      return acc; 
    }
  }

  // 2. Strip out lines starting with "System:"
  content = content.replace(/^System:.*(?:\n|$)/gm, '');

  // 3. Strip out the massive raw JSON Tool outputs 
  // (The AI already took action based on them, no need to remember the raw JSON)
  content = content.replace(/^Tool:.*(?:\n|$)/gm, '');

  // 4. Strip out the "Calling MCP Client..." logs
  content = content.replace(/^AI: Calling MCP Client.*(?:\n|$)/gm, '');

  content = content.trim();

  // If after cleaning there's nothing left, skip this row
  if (!content) return acc;

  // Add clean message to history
  acc.push(`${roleLabel}: ${content}`);
  return acc;
}, []);

// Join the clean history block
const historyBlock = cleanHistory.join("\n\n");

// Return the optimized text block
return [{ json: { conversation_history: historyBlock } }];

// ── 1. RAW INPUTS ────────────────────────────────────────────────
let language             = $('language_classifier').item.json.output.LANGUAGE;
const intent             = $('intent_classifier').item.json.output.INTENT;
const context            = $('intent_classifier').item.json.output.CONTEXT_SUMMARY;
const requiresEscalation = $('intent_classifier').item.json.output.REQUIRES_ESCALATION;
const history            = $('conversation_history').item.json.conversation_history || '';
const userMessage        = $('When chat message received').item.json.chatInput || '';
const fewShotRows        = $('Get row(s) in sheet').all();

// ── 2. SHORT-REPLY LANGUAGE CORRECTION ───────────────────────────
// Problem: "daily use", "ok", "gaming" etc. are pure English words
// but are continuation replies in a Nepali conversation.
// The classifier sees them in isolation and returns "english".
// Fix: if message is ≤3 words and history contains Nepali markers,
// override language back to romanized_nepali.

const wordCount  = userMessage.trim().split(/\s+/).length;
const isShortReply = wordCount <= 3;

if (language === 'english' && isShortReply && history) {
  const nepaliMarkers = [
    'chha', 'garnu', 'tapai', 'hunchha', 'chahanchhu',
    'milchha', 'dinus', 'hernus', 'garnechhu', 'gardinchhaun',
    'chahanuhunchha', 'sakchhu', 'bhayeko', 'aaucha', 'lagyo',
    'bhannus', 'kripaya', 'dhanyabad', 'samasya', 'sahayog'
  ];
  const historyLower   = history.toLowerCase();
  const historyIsNepali = nepaliMarkers.some(w => historyLower.includes(w));
  if (historyIsNepali) {
    language = 'romanized_nepali';
  }
}

// ── 3. FEW-SHOT EXAMPLES ─────────────────────────────────────────
const examples = fewShotRows
  .map(r => `User: ${r.json.user_input}\nAssistant: ${r.json.expected_output}`)
  .join('\n\n');

// ── 4. ESCALATION NOTE ───────────────────────────────────────────
const escalationNote = requiresEscalation
  ? '\nNOTE: REQUIRES_ESCALATION is true. Provide contact info and stop. Do not attempt to solve.\n'
  : '';

// ── 5. ASSEMBLE PROMPT ───────────────────────────────────────────
const prompt = [
  `LANGUAGE: ${language}`,
  `INTENT: ${intent}`,
  escalationNote,
  `SALES CONTEXT:\n${context}`,
  `\nEXAMPLES — respond exactly like these but never repeat:\n${examples}`,
  `\nCONVERSATION HISTORY:\n${history || 'No previous messages.'}`,
  `\nUSER QUERY: ${userMessage}`
].join('\n');

return [{ json: { prompt } }];
